// inferred-not-tested:SVGuitarChord 原生接受 HTMLElement,不需全局 selector
import { SVGuitarChord } from 'https://cdn.jsdelivr.net/npm/svguitar@2/+esm';
const el = document.getElementById('chord'); el.style.cssText = 'width:320px;max-width:100%;height:360px';
const chord = { ...data.chord, barres: data.chord.barres ?? [] };
new SVGuitarChord(el).configure({ orientation: data.config?.orientation ?? 'vertical', style: data.config?.style ?? 'normal', strings: data.config?.strings ?? 6, frets: data.config?.frets ?? 4, tuning: data.config?.tuning ?? ['E','A','D','G','B','E'] }).chord(chord).draw();

